    # 通用错误 (1000-1999)
    UNKNOWN_ERROR = 1000
    INVALID_PARAMS = 1001
    MISSING_PARAMS = 1002
    UNAUTHORIZED_ACCESS = 1401
    FORBIDDEN_ACCESS = 1403
    NOT_FOUND = 1404
    INTERNAL_ERROR = 1500

    # 用户错误 (2000-2999)
    USER_NOT_FOUND = 2001
    USER_ALREADY_EXISTS = 2002
